        ok: true,
        json: () => Promise.resolve(mockResponse)
      });

      render(<ClaudeInstanceManager />);

      await waitFor(() => {
        // Should display parsed instances
        expect(screen.getByText(/claude-7800/)).toBeInTheDocument();
        expect(screen.getByText(/claude-6548/)).toBeInTheDocument();
        expect(screen.getByText(/claude-3876/)).toBeInTheDocument();
      });
    });

    it('should handle invalid instance formats gracefully', async () => {
      const mockResponse = {
        success: true,
        instances: [
          'claude-7800 (Claude AI Interactive)',
          null, // Invalid
          'invalid-format',
          'claude-1234 (Valid Instance)'
        ]
      };

      (global.fetch as any).mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(mockResponse)
      });

      render(<ClaudeInstanceManager />);

      await waitFor(() => {
        // Should only display valid instances
        expect(screen.getByText(/claude-7800/)).toBeInTheDocument();
        expect(screen.getByText(/claude-1234/)).toBeInTheDocument();
