    });
  });

  describe('Phase 5: Real-time Synchronization', () => {
    it('should handle instance status updates via SSE', async () => {
      const mockResponse = {
        success: true,
        instances: ['claude-7800 (Claude AI Interactive)']
      };

      (global.fetch as any).mockResolvedValueOnce({
        ok: true,
